@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @GetPriorityClass()">@Task.Priority</span>
        <span class="ms-2 small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeftClick">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRightClick">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeftClick() => await OnMoveLeft.InvokeAsync();
    private async System.Threading.Tasks.Task OnMoveRightClick() => await OnMoveRight.InvokeAsync();
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">
                @(IsSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="HandleCancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<TaskItem> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    [Parameter, EditorRequired]
    public string DefaultStatus { get; set; } = "To Do";

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }

    private async System.Threading.Tasks.Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;

        IsSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(Title, Assignee, Priority, DueDate);
            await OnSave.InvokeAsync(created);
            ResetForm();
        }
        finally
        {
            IsSaving = false;
        }
    }

    private async System.Threading.Tasks.Task HandleCancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
    }
}

@* A single Kanban column: header with count, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             TaskService="TaskService"
                             OnSave="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public string? MoveLeftStatus { get; set; }

    [Parameter, EditorRequired]
    public string? MoveRightStatus { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async System.Threading.Tasks.Task HandleMoveLeft(TaskItem task)
    {
        if (MoveLeftStatus is not null)
            await OnMoveTask.InvokeAsync((task.Id, MoveLeftStatus));
    }

    private async System.Threading.Tasks.Task HandleMoveRight(TaskItem task)
    {
        if (MoveRightStatus is not null)
            await OnMoveTask.InvokeAsync((task.Id, MoveRightStatus));
    }

    private async System.Threading.Tasks.Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = "";

    [Parameter]
    public EventCallback<string> SearchTextChanged { get; set; }

    private async System.Threading.Tasks.Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTextChanged.InvokeAsync(value);
    }
}

