@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="todoTasks.Count"
                   InProgressCount="inProgressTasks.Count"
                   DoneCount="doneTasks.Count"
                   OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="filteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      MoveLeftStatus="@null"
                      MoveRightStatus="In Progress"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="filteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      MoveLeftStatus="To Do"
                      MoveRightStatus="Done"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="Done"
                      Tasks="filteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      MoveLeftStatus="In Progress"
                      MoveRightStatus="@null"
                      OnMoveTask="HandleMoveTask"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists by status (used for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Filtered lists (used for display in columns)
    private List<TaskItem> filteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> filteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> filteredDone => ApplySearch(doneTasks);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
            if (task is not null)
            {
                allTasks.Remove(task);
                allTasks.Add(task with { Status = move.NewStatus });
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="todoTasks.Count"
                   InProgressCount="inProgressTasks.Count"
